package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.*
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {
    @Transactional
    fun follow(followerId: String, followingId: String) {
        if (followerId == followingId) throw SelfFollowException()
        if (!userRepository.existsById(followerId)) throw UserNotFoundException(followerId)
        if (!userRepository.existsById(followingId)) throw UserNotFoundException(followingId)
        if (followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            throw AlreadyFollowingException(followerId, followingId)
        followRepository.save(FollowEntity(followerId = followerId, followingId = followingId))
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        if (!followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            throw NotFollowingException(followerId, followingId)
        followRepository.deleteByFollowerIdAndFollowingId(followerId, followingId)
    }

    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<UserEntity> {
        if (!userRepository.existsById(userId)) throw UserNotFoundException(userId)
        return followRepository.findByFollowingId(userId)
            .mapNotNull { userRepository.findById(it.followerId).orElse(null) }
    }

    @Transactional(readOnly = true)
    fun getFollowings(userId: String): List<UserEntity> {
        if (!userRepository.existsById(userId)) throw UserNotFoundException(userId)
        return followRepository.findByFollowerId(userId)
            .mapNotNull { userRepository.findById(it.followingId).orElse(null) }
    }
}
