package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.exception.UserNotFoundException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.whenever
import java.util.Optional

/**
 * UserService 팔로우 기능 단위 테스트.
 *
 * 대상 메서드:
 *  - follow(followerId, followingId)
 *  - unfollow(followerId, followingId)
 *  - getFollowers(userId)
 *  - getFollowings(userId)
 */
@ExtendWith(MockitoExtension::class)
class UserServiceFollowTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ─────────────────────────────────────────────────────────────────────────
    // follow()
    // ─────────────────────────────────────────────────────────────────────────

    @Test
    fun `should follow successfully when valid follower and following`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        whenever(userRepository.existsById(followerId)).thenReturn(true)
        whenever(userRepository.existsById(followingId)).thenReturn(true)
        whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(false)
        whenever(followRepository.save(any<FollowEntity>())).thenAnswer { it.arguments[0] }

        // when
        userService.follow(followerId, followingId)

        // then
        verify(followRepository).save(any())
    }

    @Test
    fun `should throw SelfFollowException when follower and following are the same user`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }

        // 자기 자신 팔로우이므로 DB 조회가 일어나지 않아야 한다
        verify(userRepository, never()).existsById(any())
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw UserNotFoundException when follower does not exist`() {
        // given
        val followerId = "non-existent-user"
        val followingId = "user-B"

        whenever(userRepository.existsById(followerId)).thenReturn(false)

        // when & then
        assertThrows<UserNotFoundException> {
            userService.follow(followerId, followingId)
        }

        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw UserNotFoundException when following target does not exist`() {
        // given
        val followerId = "user-A"
        val followingId = "non-existent-target"

        whenever(userRepository.existsById(followerId)).thenReturn(true)
        whenever(userRepository.existsById(followingId)).thenReturn(false)

        // when & then
        assertThrows<UserNotFoundException> {
            userService.follow(followerId, followingId)
        }

        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        whenever(userRepository.existsById(followerId)).thenReturn(true)
        whenever(userRepository.existsById(followingId)).thenReturn(true)
        whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followingId)
        }

        verify(followRepository, never()).save(any())
    }

    // ─────────────────────────────────────────────────────────────────────────
    // unfollow()
    // ─────────────────────────────────────────────────────────────────────────

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(true)

        // when
        userService.unfollow(followerId, followingId)

        // then
        verify(followRepository).deleteByFollowerIdAndFollowingId(followerId, followingId)
    }

    @Test
    fun `should throw NotFollowingException when trying to unfollow non-followed user`() {
        // given
        val followerId = "user-A"
        val followingId = "user-B"

        whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(false)

        // when & then
        assertThrows<NotFollowingException> {
            userService.unfollow(followerId, followingId)
        }

        verify(followRepository, never()).deleteByFollowerIdAndFollowingId(any(), any())
    }

    // ─────────────────────────────────────────────────────────────────────────
    // getFollowers()
    // ─────────────────────────────────────────────────────────────────────────

    @Test
    fun `should return followers when user exists`() {
        // given
        val userId = "user-B"
        val followerA = UserEntity(id = "user-A", nickname = "Alice")
        val followerC = UserEntity(id = "user-C", nickname = "Charlie")

        val followEntities = listOf(
            FollowEntity(followerId = "user-A", followingId = userId),
            FollowEntity(followerId = "user-C", followingId = userId),
        )

        whenever(userRepository.existsById(userId)).thenReturn(true)
        whenever(followRepository.findByFollowingId(userId)).thenReturn(followEntities)
        whenever(userRepository.findById("user-A")).thenReturn(Optional.of(followerA))
        whenever(userRepository.findById("user-C")).thenReturn(Optional.of(followerC))

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.id }).containsExactlyInAnyOrder("user-A", "user-C")
    }

    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val userId = "user-B"

        whenever(userRepository.existsById(userId)).thenReturn(true)
        whenever(followRepository.findByFollowingId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).isEmpty()
    }

    @Test
    fun `should throw UserNotFoundException when getting followers of non-existent user`() {
        // given
        val userId = "ghost-user"

        whenever(userRepository.existsById(userId)).thenReturn(false)

        // when & then
        assertThrows<UserNotFoundException> {
            userService.getFollowers(userId)
        }

        verify(followRepository, never()).findByFollowingId(any())
    }

    // ─────────────────────────────────────────────────────────────────────────
    // getFollowings()
    // ─────────────────────────────────────────────────────────────────────────

    @Test
    fun `should return followings when user exists`() {
        // given
        val userId = "user-A"
        val followingB = UserEntity(id = "user-B", nickname = "Bob")
        val followingC = UserEntity(id = "user-C", nickname = "Charlie")

        val followEntities = listOf(
            FollowEntity(followerId = userId, followingId = "user-B"),
            FollowEntity(followerId = userId, followingId = "user-C"),
        )

        whenever(userRepository.existsById(userId)).thenReturn(true)
        whenever(followRepository.findByFollowerId(userId)).thenReturn(followEntities)
        whenever(userRepository.findById("user-B")).thenReturn(Optional.of(followingB))
        whenever(userRepository.findById("user-C")).thenReturn(Optional.of(followingC))

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.id }).containsExactlyInAnyOrder("user-B", "user-C")
    }

    @Test
    fun `should return empty list when user follows nobody`() {
        // given
        val userId = "user-A"

        whenever(userRepository.existsById(userId)).thenReturn(true)
        whenever(followRepository.findByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
    }

    @Test
    fun `should throw UserNotFoundException when getting followings of non-existent user`() {
        // given
        val userId = "ghost-user"

        whenever(userRepository.existsById(userId)).thenReturn(false)

        // when & then
        assertThrows<UserNotFoundException> {
            userService.getFollowings(userId)
        }

        verify(followRepository, never()).findByFollowerId(any())
    }

    @Test
    fun `should skip deleted user entities when returning followings`() {
        // given — user-C 가 탈퇴하여 DB 에서 조회되지 않는 엣지 케이스
        val userId = "user-A"
        val followingB = UserEntity(id = "user-B", nickname = "Bob")

        val followEntities = listOf(
            FollowEntity(followerId = userId, followingId = "user-B"),
            FollowEntity(followerId = userId, followingId = "user-C"), // 탈퇴 유저
        )

        whenever(userRepository.existsById(userId)).thenReturn(true)
        whenever(followRepository.findByFollowerId(userId)).thenReturn(followEntities)
        whenever(userRepository.findById("user-B")).thenReturn(Optional.of(followingB))
        whenever(userRepository.findById("user-C")).thenReturn(Optional.empty()) // 탈퇴

        // when
        val result = userService.getFollowings(userId)

        // then — 탈퇴 유저는 목록에서 제외되어야 한다
        assertThat(result).hasSize(1)
        assertThat(result[0].id).isEqualTo("user-B")
    }
}
